// Script Continued Below
var TaskTemplateHelpers = Class.create();
TaskTemplateHelpers.prototype = {
    initialize: function() {
    },

	getDurationDaysAndTimeDue: function (gr) {
		var objDuration = {"u_duration_days":0,"u_duration_time_due":0};
		var duration;
		if(!gr.u_duration_days.nil()){
			objDuration.u_duration_days = gr.u_duration_days;
		} else if(!gr.u_duration.nil()){
			// STRY0110317
			duration = new GlideDateTime(gr.getValue('u_duration'));
			// get duration into miliseconds
			duration = duration.getNumericValue();
			// this will set the day field
			objDuration.u_duration_days = this.calculateDaysFromDuration(duration);
		}
		// if time set, return time
		if(!gr.u_duration_time_due.nil()){
			duration = new GlideDateTime(gr.getValue('u_duration_time_due'));
			objDuration.u_duration_time_due = duration.getNumericValue();
		} else{
			// if time not set, return system default
			var eod_string = new tasking_System_Settings_Scripts().getDefaultTime(gr);
			duration = new GlideDateTime(eod_string);
			// get duration into miliseconds
			duration = duration.getNumericValue();
			objDuration.u_duration_time_due = this.calculateTimeFromDuration(duration);
		}
		return objDuration;
	},
	calculateDaysFromDuration: function(durationMS){
		var days = 0;
		var dueTime = 0;
		var oneDay = (24 * 60 * 60) * 1000;
		if (durationMS >= oneDay) {
			days = parseInt(durationMS / oneDay);
		}
		return days;
	},


	calculateTimeFromDuration: function(durationMS){
		var dueTime;
		var days = this.calculateDaysFromDuration(durationMS);
		var oneDay = (24 * 60 * 60) * 1000;
		if (days > 0) {
			// get time by subtracting the value of all the days in milliseconds from the durationMS var
			dueTime = durationMS - (days * oneDay);
		} else {
			dueTime = durationMS;
		}

		return dueTime;
	},

	// NOTE the math in this function needs to stay in sync with getTemplateTreeLeveln as bothare setting warnings
	getTemplateTaskDurationOfChildren: function (sys_id) {
		// STRY0110317 
		var tdc = new TaskerDurationCalculator();
		var grTempTask = new GlideRecordSecure('x_153465_discovert_route_tasks');
		grTempTask.addQuery('parent', sys_id);
		grTempTask.orderBy('route_order');
		grTempTask.query();

		// these the variables are used to build the duration total at each level
		var sumSubTaskTemplateDuration = 0;
		var currentOrder = 0;
		var orderMax = 0;
		while (grTempTask.next()) {
			// order changed, reset orderMax
			if (currentOrder != grTempTask.route_order){
				sumSubTaskTemplateDuration += orderMax;
				orderMax = 0;
				currentOrder = parseInt(grTempTask.route_order);
			}
			// STRY0110317 calculate the due date to be set using days and Time
			var taskActualTime = 0;
			if(grTempTask.u_duration_days > 0){
				taskActualTime = grTempTask.u_duration_days * 86400000;
			}
			if(!grTempTask.u_duration_time_due.nil()){
				taskActualTime+= grTempTask.u_duration_time_due.dateNumericValue();
			}
			if (taskActualTime > orderMax){
				orderMax = parseInt(taskActualTime);
			}
		}
		return sumSubTaskTemplateDuration + orderMax;
	},

