	//                  u_internal_contact_performing_task
	//					u_reviewer
	//					u_on_behalf_of
	loadTemplateAndTaskIntoInstanceForm: function(data_f_fields, templateID, parentTaskID) {
		// for each field that can be in the input, check to see if it is provided.
		// if it is not provided, see if the associated Template field has a value.
		// if the field was not provided, but the associated tempalte has a value, the set the field to the template field.
		// check values in input and override values from the Template
		var grTemp = new GlideRecordSecure('x_153465_discovert_discover_routing_template');
		var grTask = new GlideRecord('x_153465_discovert_route_task_instance');
		// STRY0075793 - run templates from task in native
		if (data_f_fields == '')
			data_f_fields = this.createEmptyTemplateFieldsJSON();
		if(grTemp.get(templateID)){
			data_f_fields.routing_template_ref.value = templateID;
			data_f_fields.routing_template_ref.displayValue = grTemp.getDisplayValue();
			data_f_fields.discover_template_name.value = grTemp.template_name + '';
			data_f_fields.discover_template_name.displayValue = grTemp.getDisplayValue("template_name");

			data_f_fields.short_description.value = grTemp.getValue("short_description");
			data_f_fields.short_description.displayValue = grTemp.getDisplayValue("short_description");
			// STRY0085139 - pull classification from the template instead of Task
			data_f_fields.classification.value = grTemp.getValue("classification");

			// STRY0084306
			data_f_fields.u_template_subtask_s_name_setting.value = grTemp.getValue("u_template_subtask_s_name_setting");
			// STRY0084419, STRY0084420, STRY0084424
			data_f_fields.u_subtask_s_name_modifier.value = '';
			data_f_fields.u_subtask_s_name_modifier.displayValue = '';

			data_f_fields.instance_notation.value = grTemp.getValue("description");
			data_f_fields.instance_notation.displayValue = grTemp.getDisplayValue("description");

			// STRY0075864
			data_f_fields.u_external_ou.value = grTemp.getValue("u_external_ou");
			data_f_fields.u_external_ou.displayValue = grTemp.getDisplayValue("u_external_ou");

			data_f_fields.poc_name.value = grTemp.getValue("poc_name");
			data_f_fields.poc_name.displayValue = grTemp.getDisplayValue("poc_name");
			data_f_fields.outbound.value = (grTemp.outbound == true) ? 'true' : 'false';
			data_f_fields.u_internal_contact.value = grTemp.getValue("u_internal_contact");
			data_f_fields.u_internal_contact.displayValue = grTemp.getDisplayValue("u_internal_contact");
			data_f_fields.u_internal_contact_performing_task.value = (grTemp.u_internal_contact_performing_task == true) ? 'true' : 'false';
			// STRY0085139 
			data_f_fields.u_on_behalf_of.value = grTemp.u_on_behalf_of +'';
			data_f_fields.u_on_behalf_of.displayValue = grTemp.getDisplayValue("u_on_behalf_of");

		}
		if(grTask.get(parentTaskID)){
			// Laod the fields coming from the Parent Task
			data_f_fields.parent_task.value = parentTaskID;
			data_f_fields.parent_task.displayValue = grTask.getDisplayValue();
			// STRY0085139 - pull classification from the template instead of Task
			//data_f_fields.classification.value = grTask.getValue("classification");

			data_f_fields.u_objective.value = grTask.u_objective + '';
			data_f_fields.u_objective.displayValue = grTask.getDisplayValue("u_objective");

			data_f_fields.u_restricted_group.value = grTask.assignment_group + '';
			data_f_fields.u_restricted_group.displayValue = grTask.getDisplayValue("assignment_group");

			data_f_fields.u_tasking_authority.value = grTask.tasking_authority + '';
			data_f_fields.u_tasking_authority.displayValue = grTask.getDisplayValue("tasking_authority");

			data_f_fields.u_primary_office.value = grTask.primary_office + '';
			data_f_fields.u_primary_office.displayValue = grTask.getDisplayValue("primary_office");

			data_f_fields.u_primary_assignee.value = grTask.primary_assignee +'';
			data_f_fields.u_primary_assignee.displayValue = grTask.getDisplayValue("primary_assignee");

			data_f_fields.u_assigned_member.value = grTask.assigned_to +'';
			data_f_fields.u_assigned_member.displayValue = grTask.getDisplayValue("assigned_to");

			// STRY0085139 
			data_f_fields.u_reviewer.value = grTask.u_reviewer +'';
			data_f_fields.u_reviewer.displayValue = grTask.getDisplayValue("u_reviewer");

			data_f_fields.originator.value = gs.getUserID();
			data_f_fields.originator.displayValue = gs.getUserDisplayName();

		}
		// STRY0084599 - Need a way for deliver and customers to better synchronize field updates and changes
		return new CustomTaskerFieldHelper().loadCustomFieldsFromTemplateAndTaskIntoInstanceForm(data_f_fields, grTemp, grTask);
	},

	// This function loads the data fields objects with the data from teh template instance provided
 	// It returns a data.f._fields object loaded with the default values for a Template
 	// inputs ---------------------------------------------------------------------
 	// template     -> Template Glide Record
 	// RETURN - --------------------------------------------------------------------- 
 	//   JSON object with the following values
 	//                  templateName
 	//                  classification
 	//                  templateNotation
 	//                  shortDescription
	//                  u_template_subtask_s_name_setting
	//                  u_subtask_s_name_modifier
 	//                  tableName
 	//                  tableSysID
 	//                  assignedMember
 	//                  objective
 	//                  primaryAssignee
 	//                  primaryOffice
 	//                  restrictedGroup
 	//                  taskingAuthority	
	//                  u_external_ou
	//                  poc_name
	//                  outbound
	//                  u_internal_contact
	//                  u_internal_contact_performing_task
